import sqlite3
from cryptography.fernet import Fernet

def encrypt_and_store_user_data(db_path, user_id, sensitive_data, encryption_key):
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE IF NOT EXISTS user_data (user_id TEXT, encrypted_data TEXT)')
    fernet = Fernet(encryption_key)
    encrypted_text = fernet.encrypt(sensitive_data.encode('utf-8')).decode('utf-8')
